import { ref } from 'vue'
import { useStore } from 'vuex'
import { auth } from '@/api/auth'
import { sms } from '@/api/sms'
import { SMS_SCENE } from '@/constants'
import { showToast } from '@/components/ToastMessage'

export function usePhone() {
  const store = useStore()

  // 状态
  const showPhoneModal = ref(false)
  const newPhone = ref('')
  const phoneVerifyCode = ref('')
  const phoneCodeCountdown = ref(0)
  const loading = ref(false)

  // 验证手机号
  const validatePhone = (phone) => {
    if (!phone) {
      showToast('请输入手机号', 'warning')
      return false
    }

    const phoneRegex = /^1[3-9]\d{9}$/
    if (!phoneRegex.test(phone)) {
      showToast('请输入正确的手机号', 'warning')
      return false
    }

    return true
  }

  // 发送验证码
  const handleSendPhoneCode = async () => {
    if (!validatePhone(newPhone.value)) return

    try {
      await sms.sendVerifyCode({
        phone: newPhone.value,
        scene: SMS_SCENE.CHANGE_PHONE
      })

      showToast('验证码已发送', 'success')
      // 开始倒计时
      phoneCodeCountdown.value = 60
      const timer = setInterval(() => {
        phoneCodeCountdown.value--
        if (phoneCodeCountdown.value <= 0) {
          clearInterval(timer)
        }
      }, 1000)
    } catch (error) {
      showToast(error.message || '发送验证码失败', 'error')
    }
  }

  // 关闭弹窗
  const closePhoneModal = () => {
    showPhoneModal.value = false
    newPhone.value = ''
    phoneVerifyCode.value = ''
  }

  // 更新手机号
  const handleUpdatePhone = async () => {
    if (!validatePhone(newPhone.value)) return

    if (!phoneVerifyCode.value) {
      showToast('请输入验证码', 'warning')
      return
    }

    try {
      loading.value = true
      const response = await auth.changePhone({
        phone: newPhone.value,
        code: phoneVerifyCode.value
      })

      if (response.data?.code === 200) {
        // 更新 store 中的 userInfo
        store.commit('SET_USER_INFO', {
          ...store.state.userInfo,
          phone: newPhone.value
        })

        // 同时更新 basicInfo 中的手机号
        store.commit('SET_BASIC_INFO', {
          ...store.state.basicInfo,
          phone: newPhone.value
        })

        showToast('手机号更新成功', 'success')
        closePhoneModal()
      }
    } catch (error) {
      showToast(error.message || '更新手机号失败', 'error')
    } finally {
      loading.value = false
    }
  }

  // 打开弹窗
  const openPhoneModal = () => {
    showPhoneModal.value = true
  }

  // 手机号脱敏处理
  const maskPhone = (phone) => {
    if (!phone) return '未绑定'
    return phone.replace(/(\d{3})\d{4}(\d{4})/, '$1****$2')
  }

  return {
    showPhoneModal,
    newPhone,
    phoneVerifyCode,
    phoneCodeCountdown,
    loading,
    handleSendPhoneCode,
    handleUpdatePhone,
    openPhoneModal,
    closePhoneModal,
    maskPhone
  }
}
